string MeilleurEtudiant(Dictionary<string, List<int>> d)
{
    string meilleurNom = null;
    double meilleureMoyenne = -1;
    foreach (var kvp in d)
    {
        double moyenne = kvp.Value.Average();
        if (moyenne > meilleureMoyenne)
        {
            meilleureMoyenne = moyenne;
            meilleurNom = kvp.Key;
        }
    }
    return meilleurNom;
}

